  <div>
    <h1>Base</h1>
    <Message mb={40}>Hello world</Message>
<h1>Centered + Elevation 4</h1>
<Message isCentered bg="secondary" mb={40} w={300} h={200} elevation={4}>Hello world</Message>

<h1>Text aligned + Width</h1>
<Message isDark bg="dark" c="light" w="100%" textAlign="left">Hello world</Message>
  </div>
</Playground>
           </MDXTag>
  }
}
